// 生成搜索查询列表
const config = JSON.parse($json.monitorConfig);
const keywords = JSON.parse($json.keywords);

const queries = [];

// 百度收录查询
queries.push({
  type: 'baidu_index',
  searchUrl: `https://www.baidu.com/s?wd=site:${config.siteUrl}&rn=10`,
  keyword: '全站收录'
});

// 关键词排名查询
for (const kw of keywords) {
  queries.push({
    type: 'keyword_rank',
    searchUrl: `https://www.baidu.com/s?wd=${encodeURIComponent(kw + ' ' + config.siteName)}&rn=10`,
    keyword: kw
  });
}

// 竞品对比查询
for (const competitor of config.competitors) {
  queries.push({
    type: 'competitor_rank',
    searchUrl: `https://www.baidu.com/s?wd=${encodeURIComponent(keywords[0] + ' ' + competitor)}&rn=5`,
    keyword: keywords[0],
    competitor: competitor
  });
}

return queries;

// 解析搜索结果，提取收录/排名信息
const responseText = $input.first().json.response || '';
const queryType = $json.type;
const keyword = $json.keyword;
const siteUrl = 'dajilin.net';

let result = {
  type: queryType,
  keyword: keyword,
  competitor: $json.competitor || null,
  indexed: false,
  rank: null,
  totalResults: null,
  ourSitePresent: false,
  competitorPresent: false,
  checkedAt: new Date().toISOString(),
  rawSnippet: ''
};

// 提取百度结果数量
const resultCountMatch = responseText.match(/百度为您找到相关结果约([0-9,，]+)个/);
if (resultCountMatch) {
  result.totalResults = parseInt(resultCountMatch[1].replace(/,/g, ''));
}

// 检查我们网站是否在结果中
if (responseText.includes(siteUrl)) {
  result.ourSitePresent = true;
  // 提取我们网站出现的位置
  const index = responseText.indexOf(siteUrl);
  // 粗略估算排名（每个结果约100-150字符）
  result.rank = Math.ceil(index / 130);
}

// 标记为已收录
if (queryType === 'baidu_index') {
  result.indexed = result.ourSitePresent;
}

// 提取相关 snippet 用于分析
const snippetMatch = responseText.match(new RegExp(`${siteUrl}[^<]{0,200}`));
if (snippetMatch) {
  result.rawSnippet = snippetMatch[0].substring(0, 200);
}

return [result];

// 聚合所有监控结果
const results = $input.all();
const config = JSON.parse($json.monitorConfig);

const summary = {
  reportDate: new Date().toLocaleString('zh-CN'),
  siteUrl: config.siteUrl,
  totalChecks: results.length,
  indexed: results.filter(r => r.type === 'baidu_index' && r.indexed).length > 0,
  keywordRankings: [],
  competitorsTracked: config.competitors,
  recommendations: []
};

// 统计关键词排名
for (const r of results) {
  if (r.type === 'keyword_rank') {
    summary.keywordRankings.push({
      keyword: r.keyword,
      rank: r.rank,
      present: r.ourSitePresent
    });
  }
}

// 生成建议
const topKeywords = summary.keywordRankings.filter(k => k.rank && k.rank <= 10);
if (topKeywords.length > 0) {
  summary.recommendations.push(`✅ ${topKeywords.length}个关键词进入前10`);
}

const midKeywords = summary.keywordRankings.filter(k => k.rank && k.rank > 10 && k.rank <= 50);
if (midKeywords.length > 0) {
  summary.recommendations.push(`📈 ${midKeywords.length}个关键词在11-50位，可通过外链提升`);
}

const noRankKeywords = summary.keywordRankings.filter(k => !k.rank);
if (noRankKeywords.length > 0) {
  summary.recommendations.push(`⚠️ ${noRankKeywords.length}个关键词未找到排名，建议：1) 增加内容 2) 提交sitemap 3) 获取外链`);
}

return [summary];

// 生成监控报告
const summary = $input.first().json;

let html = `<h2>外部GEO收录监控报告</h2>
<p><strong>监控时间:</strong> ${summary.reportDate}</p>
<p><strong>监测网站:</strong> ${summary.siteUrl}</p>

<h3>收录状态</h3>
<p>${summary.indexed ? '✅ 已被百度收录' : '❌ 暂未被百度收录'}</p>

<h3>关键词排名</h3>
<table border='1' style='border-collapse: collapse;'>
<tr><th>关键词</th><th>排名</th><th>状态</th></tr>`;

for (const kw of summary.keywordRankings) {
  let status = '❌ 未收录';
  if (kw.rank && kw.rank <= 10) status = '✅ 前10';
  else if (kw.rank && kw.rank <= 50) status = '📈 11-50';
  else if (kw.rank) status = `📍 第${kw.rank}位`;

  html += `<tr><td>${kw.keyword}</td><td>${kw.rank || '-'}</td><td>${status}</td></tr>`;
}
html += '</table>';

html += `<h3>优化建议</h3>
<ul>`;
for (const rec of summary.recommendations) {
  html += `<li>${rec}</li>`;
}
html += '</ul>';

html += `<h3>下一步行动</h3>
<ol>
<li>对于未收录关键词：在对应平台发布内容并获取外链</li>
<li>对于排名11-50的关键词：加强内部链接和内容质量</li>
<li>持续监控竞品外链策略</li>
</ol>

<p><small>由n8n自动生成 | ${new Date().toISOString()}</small></p>`;

return [{ html, summary }];
